import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const y=JSON.parse('{"title":"通貨一覧","description":"","frontmatter":{},"headers":[],"relativePath":"ja/items/currency.md","filePath":"ja/items/currency.md","lastUpdated":1775394001000}'),i={name:"ja/items/currency.md"};function r(n,t,s,h,f,o){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="通貨一覧" tabindex="-1">通貨一覧 <a class="header-anchor" href="#通貨一覧" aria-label="Permalink to &quot;通貨一覧&quot;">​</a></h1><p>忘却前夜のゲーム内通貨の一覧と入手方法です。</p><h2 id="主要通貨" tabindex="-1">主要通貨 <a class="header-anchor" href="#主要通貨" aria-label="Permalink to &quot;主要通貨&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">通貨</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">源液 (Silver Prime)</td><td style="text-align:left;">課金通貨。召喚、通行証、外観、ギフトボックスの購入</td><td style="text-align:left;">課金購入</td></tr><tr><td style="text-align:left;">銀芯 (Silver Core)</td><td style="text-align:left;">主要無課金通貨。流明之芯・無垢之芯への交換、墨諾芬回復（50銀芯=120墨諾芬）</td><td style="text-align:left;">デイリーミッション、メインステージ評価、手帳、幻夢深潜、イベント、通行証、交換コード</td></tr><tr><td style="text-align:left;">墨諾芬 (Menophine)</td><td style="text-align:left;">スタミナ/行動力。幕間演習の消費に使用</td><td style="text-align:left;">自然回復、銀芯交換、アイテム/ギフトボックス</td></tr><tr><td style="text-align:left;">蔷薇金券 (Rose Scrip)</td><td style="text-align:left;">汎用通貨。ショップ購入、教化、錬金、素材合成、運命の輪重畳、密契写本（7500/回）</td><td style="text-align:left;">メインステージ初回通関、融蝕之墟、外勤代理、課程、運命の輪分解（青=1000, 紫=4000）</td></tr></tbody></table><h2 id="召喚-ガチャ-通貨" tabindex="-1">召喚（ガチャ）通貨 <a class="header-anchor" href="#召喚-ガチャ-通貨" aria-label="Permalink to &quot;召喚（ガチャ）通貨&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">通貨</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">流明之芯 (Lumen Core)</td><td style="text-align:left;">限定池召喚通貨（1個=1回）</td><td style="text-align:left;">銀芯交換（優先推奨）、イベント報酬、通行証</td></tr><tr><td style="text-align:left;">無垢之芯 (Pure Core)</td><td style="text-align:left;">常驻池召喚通貨（1個=1回）</td><td style="text-align:left;">銀芯交換、イベント報酬、キャラ初回昇格報酬、通行証無料トラック（40個）、チャプター初通関</td></tr><tr><td style="text-align:left;">沈澱幣 (Sediment Currency)</td><td style="text-align:left;">沈澱ショップ交換。密契セット（猩红之拥）、追念羽筆（80沈澱=10本/週）、原初霊核購入</td><td style="text-align:left;">召喚（唤醒）時の副産物</td></tr></tbody></table><h2 id="ショップ通貨" tabindex="-1">ショップ通貨 <a class="header-anchor" href="#ショップ通貨" aria-label="Permalink to &quot;ショップ通貨&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">通貨</th><th style="text-align:left;">用途</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">調査徽章 (Investigation Badge)</td><td style="text-align:left;">調査ショップ。追念羽筆（800徽章=5本/週）の購入</td><td style="text-align:left;">メインステージ三つ星通関、秘術統御、霊魂潜行三つ星、個人成就（300/個）</td></tr><tr><td style="text-align:left;">無光幣 (Lightless Currency)</td><td style="text-align:left;">無光ショップ。密契セット（远方的欢宴）、追念羽筆（800=5/週）の購入</td><td style="text-align:left;">無光秘境、界域異効区</td></tr><tr><td style="text-align:left;">融蝕之珠 (D-Jewels)</td><td style="text-align:left;">深潜ショップ。追念羽筆（800=5/週）、碎裂余夢（100/週）、群星余夢（25/週）の購入。算出：(幻夢等級+2)x100</td><td style="text-align:left;">幻夢深潜（三級=500, 狂気=900）、外勤代理（毎日精算）</td></tr><tr><td style="text-align:left;">相位幣 (Phase Coin)</td><td style="text-align:left;">相位ショップ。密契セット（猩红之悸）、追念羽筆（800=5/週）の購入</td><td style="text-align:left;">相位対弈（PVP）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>召喚通貨はメインステージ初回クリア報酬やデイリーミッションで入手できます。天井の30連分（＝召喚通貨30回分）を目標に貯めましょう。流明之芯は入手手段が限られるため、銀芯交換では流明之芯を優先してください。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">アイテム概要</a></li><li><a href="./../modes/gacha.html">召喚システム</a></li><li><a href="./../guides/beginner.html">初心者ガイド</a></li></ul>',11)])])}const g=e(i,[["render",r]]);export{y as __pageData,g as default};
